optimized_federated_query:
# Smart Federated Query with Class Constraints
# Note: Multiple class interpretations exist but all route to same endpoints
# A single query retrieves all data regardless of class ambiguity

SELECT DISTINCT ?author ?role ?paper ?place ?capital ?latitude ?longitude ?proceedings
WHERE {

  SERVICE <http://localhost:8891/sparql/> {
    ?place <http://www.w3.org/2003/01/geo/wgs84_pos#lat> ?latitude . # ?place:BaseballPlayer, ?latitude:Literal
    ?place <http://www.w3.org/2003/01/geo/wgs84_pos#long> ?longitude . # ?place:Senator, ?longitude:Literal
    ?place <http://dbpedia.org/ontology/capital> ?capital . # ?place:Country, ?capital:Country
  }

  SERVICE <http://localhost:8898/sparql/> {
    ?proceedings <http://data.semanticweb.org/ns/swc/ontology#relatedToEvent> <http://data.semanticweb.org/conference/eswc/2010> . # ?proceedings:Proceedings
    ?role <http://data.semanticweb.org/ns/swc/ontology#isRoleAt> <http://data.semanticweb.org/conference/eswc/2010> . # ?role:Chair
    ?role <http://data.semanticweb.org/ns/swc/ontology#heldBy> ?author . # ?role:IW3C2Liaison, ?author:Person
    ?author <http://xmlns.com/foaf/0.1/based_near> ?place . # ?author:Place, ?place:Thing
    ?paper <http://data.semanticweb.org/ns/swc/ontology#isPartOf> ?proceedings . # ?paper:InProceedings, ?proceedings:Proceedings
    ?paper <http://swrc.ontoware.org/ontology#author> ?author . # ?paper:SystemDescription, ?author:Person
  }
}
LIMIT 1000
